+        "Exception",
+        "BaseException",
+        "RuntimeError",
+        "ValueError",
+        "TypeError",
+        "KeyError",
+        "IndexError",
+        "AttributeError",
+        "NameError",
+        "IOError",
+        "OSError",
+        "FileNotFoundError",
+        "PermissionError",
+        "ZeroDivisionError",
+        "OverflowError",
+        "NotImplementedError",
+        "StopIteration",
+        "AssertionError",
+        "ImportError",
+        "ModuleNotFoundError",
+        "LookupError",
+        "UnicodeError",
+        "UnicodeDecodeError",
+        "UnicodeEncodeError",
+        "SystemError",
+        "RecursionError",
+        "MemoryError",
+        "BufferError",
+        "ConnectionError",
+        "TimeoutError",
+    };
+    for (exception_types) |exc_name| {
+        if (std.mem.eql(u8, func_name, exc_name)) {
+            return .{ .exception = exc_name };
+        }
+    }
+
+    return .unknown;
+}

