+/// Check if an expression produces a Zig block expression that needs parentheses
+fn producesBlockExpression(expr: ast.Node) bool {
+    return switch (expr) {
+        .subscript => true,
+        .list => true,
+        .dict => true,
+        .listcomp => true,
+        .dictcomp => true,
+        .genexp => true,
+        .if_expr => true,
+        .call => true,
+        .attribute => true,
+        .compare => true,
+        else => false,
+    };
