+/// Generate expression, wrapping in parentheses if it's a block expression
+fn genExprWrapped(self: *NativeCodegen, expr: ast.Node) CodegenError!void {
+    if (producesBlockExpression(expr)) {
+        try self.emit("(");
+        try genExpr(self, expr);
+        try self.emit(")");
+    } else {
+        try genExpr(self, expr);
+    }
+}
