+        const is_used = var_tracking.isParamUsedInStmts(arg.name, func.body);
+        if (is_used) {
+            try self.output.writer(self.allocator).print("__p_{s}_{d}: anytype", .{ arg.name, saved_counter });
+        } else {
+            try self.emit("_: anytype");
+        }
+    }
+    try self.emit(") void {\n");
+    self.indent();
+
+    // Generate body
+    try self.pushScope();
+
